#include <bits/stdc++.h>
using namespace std;
long long t, n, m, l, a[1005], c[1005][1005];
int main() {
	for (int i = 0; i < 1005; i++)
		for (int j = 0; j <= i; j++)
			if (j == 0) c[i][j] = 1;
			else c[i][j] = (c[i - 1][j] + c[i - 1][j - 1]) % 1000000007;
	cin >> t;

	while (t--) {
		cin >> n >> m;
		long long sum = 0;
		for (int i = 1; i <= m; i++) {
			cin >> a[i];
			sum += a[i];
		}
		long long ans = 1;
		for (int j = 1, l = n + (sum > n); j <= m; j++) {
			ans = (ans * c[l][a[j]]) % 1000000007;
			l -= a[j];
		}
		cout << ans % 1000000007 << endl;
	}
	return 0;
}
